import functools
from flask import Flask, request, jsonify, g
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime
import secrets

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///oauth.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)


class AccessToken(db.Model):
    __tablename__ = 'access_tokens'
    
    id = db.Column(db.Integer, primary_key=True)
    token = db.Column(db.String(255), unique=True, nullable=False, index=True)
    user_id = db.Column(db.String(100), nullable=False)
    client_id = db.Column(db.String(100), nullable=False)
    scopes = db.Column(db.String(500), default='')
    issued_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    revoked = db.Column(db.Boolean, default=False)
    
    def is_valid(self):
        if self.revoked:
            return False
        if datetime.utcnow() > self.expires_at:
            return False
        return True
    
    def has_scope(self, required_scope):
        if not required_scope:
            return True
        token_scopes = set(self.scopes.split())
        return required_scope in token_scopes


def get_token_from_request():
    auth_header = request.headers.get('Authorization', '')
    
    if auth_header.startswith('Bearer '):
        return auth_header[7:]
    
    return request.args.get('access_token') or request.form.get('access_token')


def require_oauth(scopes=None):
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            token_string = get_token_from_request()
            
            if not token_string:
                return jsonify({
                    'error': 'invalid_request',
                    'error_description': 'Missing access token'
                }), 401
            
            access_token = AccessToken.query.filter_by(token=token_string).first()
            
            if not access_token:
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'Token not found'
                }), 401
            
            if not access_token.is_valid():
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'Token is expired or revoked'
                }), 401
            
            if scopes:
                required_scopes = scopes if isinstance(scopes, list) else [scopes]
                for scope in required_scopes:
                    if not access_token.has_scope(scope):
                        return jsonify({
                            'error': 'insufficient_scope',
                            'error_description': f'Token does not have required scope: {scope}'
                        }), 403
            
            g.current_token = access_token
            g.current_user_id = access_token.user_id
            g.current_client_id = access_token.client_id
            
            return f(*args, **kwargs)
        
        return decorated_function
    return decorator


