@app.route('/oauth/token/validate', methods=['POST'])
def validate_token():
    token_string = request.json.get('token') if request.json else None
    
    if not token_string:
        return jsonify({
            'valid': False,
            'error': 'Token not provided'
        }), 400
    
    access_token = AccessToken.query.filter_by(token=token_string).first()
    
    if not access_token:
        return jsonify({
            'valid': False,
            'error': 'Token not found'
        })
    
    if not access_token.is_valid():
        return jsonify({
            'valid': False,
            'error': 'Token expired or revoked'
        })
    
    return jsonify({
        'valid': True,
        'user_id': access_token.user_id,
        'client_id': access_token.client_id,
        'scopes': access_token.scopes.split(),
        'expires_at': access_token.expires_at.isoformat()
    })


@app.route('/oauth/token/introspect', methods=['POST'])
def introspect_token():
    token_string = request.form.get('token')
    
    if not token_string:
        return jsonify({
            'active': False
        })
    
    access_token = AccessToken.query.filter_by(token=token_string).first()
    
    if not access_token or not access_token.is_valid():
        return jsonify({
            'active': False
        })
    
    return jsonify({
        'active': True,
        'scope': access_token.scopes,
        'client_id': access_token.client_id,
        'user_id': access_token.user_id,
        'exp': int(access_token.expires_at.timestamp()),
        'iat': int(access_token.issued_at.timestamp())
    })


@app.route('/oauth/token/revoke', methods=['POST'])
def revoke_token():
    token_string = request.form.get('token')
    
    if not token_string:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'Token not provided'
        }), 400
    
    access_token = AccessToken.query.filter_by(token=token_string).first()
    
    if access_token:
        access_token.revoked = True
        db.session.commit()
    
    return jsonify({
        'message': 'Token revoked successfully'
    })


@app.route('/oauth/token/create', methods=['POST'])
def create_token():
    data = request.json or {}
    
    user_id = data.get('user_id')
    client_id = data.get('client_id')
    scopes = data.get('scopes', '')
    expires_in = data.get('expires_in', 3600)
    
    if not user_id or not client_id:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'user_id and client_id are required'
        }), 400
    
    token_string = secrets.token_urlsafe(32)
    
    access_token = AccessToken(
        token=token_string,
        user_id=user_id,
        client_id=client_id,
        scopes=scopes if isinstance(scopes, str) else ' '.join(scopes),
        issued_at=datetime.utcnow(),
        expires_at=datetime.utcnow().replace(second=0, microsecond=0).timestamp() + expires_in
    )
    
    from datetime import timedelta
    access_token.expires_at = datetime.utcnow() + timedelta(seconds=expires_in)
    
    db.session.add(access_token)
    db.session.commit()
    
    return jsonify({
        'access_token': token_string,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scope': access_token.scopes
    })


